// Mirrors React-template CallToAction.jsx — cta-style-01 (banner), cta-style-02 (centered)

interface CTAProps {
  theme?: "cta-style-01" | "cta-style-02";
  subheading?: string;
  heading: string;
  description?: string;
  primaryBtn?: { label: string; link: string };
  secondaryBtn?: { label: string; link: string };
}

export default function CallToAction({ theme = "cta-style-01", subheading, heading, description, primaryBtn, secondaryBtn }: CTAProps) {
  if (theme === "cta-style-02") {
    return (
      <div className="cta-02">
        {subheading && <p className="cta-sub">{subheading}</p>}
        <h2>{heading}</h2>
        {description && <p>{description}</p>}
        <div className="flex items-center justify-center gap-4 flex-wrap">
          {primaryBtn && <a href={primaryBtn.link} className="btn btn-fancy-primary btn-lg">{primaryBtn.label}</a>}
          {secondaryBtn && <a href={secondaryBtn.link} className="btn btn-fancy-outline btn-lg">{secondaryBtn.label}</a>}
        </div>
      </div>
    );
  }

  return (
    <div className="cta-01">
      <div className="cta-text">
        {subheading && <p className="text-[--primary] text-xs font-bold tracking-widest uppercase mb-1">{subheading}</p>}
        <h3>{heading}</h3>
        {description && <p>{description}</p>}
      </div>
      <div className="cta-actions">
        {primaryBtn && <a href={primaryBtn.link} className="btn btn-fancy-primary">{primaryBtn.label}</a>}
        {secondaryBtn && <a href={secondaryBtn.link} className="btn btn-fancy-outline-white">{secondaryBtn.label}</a>}
      </div>
    </div>
  );
}
