// Mirrors React-template PricingTable01.jsx and PricingTable02.jsx

import type { ReactNode } from "react";

export interface PricingPlan {
  title: string;
  subtitle?: string;
  price: string;
  term: string;
  plans: string[];
  buttonTitle?: string;
  buttonLink?: string;
  isPopular?: boolean;
  icon?: ReactNode;
}

interface Props {
  theme?: "pricing-table-01" | "pricing-table-02" | "pricing-table-03" | "pricing-table-04";
  data: PricingPlan[];
  grid?: string;
}

export default function PricingTable({ theme = "pricing-table-01", data, grid = "grid-cols-1 sm:grid-cols-2 lg:grid-cols-3" }: Props) {
  return (
    <div className={`grid ${grid} gap-6`}>
      {data.map((item, i) => {
        if (theme === "pricing-table-02") return <Style02 key={i} item={item} />;
        if (theme === "pricing-table-03") return <Style03 key={i} item={item} />;
        if (theme === "pricing-table-04") return <Style04 key={i} item={item} />;
        return <Style01 key={i} item={item} />;
      })}
    </div>
  );
}

function Style03({ item }: { item: PricingPlan }) {
  const numericPrice = /^\d/.test(item.price);
  return (
    <div className={`pt-03 ${item.isPopular ? "popular" : ""}`}>
      {item.isPopular && <div className="pt-badge">Most Popular</div>}
      {item.icon && <div className="pt-icon">{item.icon}</div>}
      <div className="pt-name">{item.title}</div>
      <div className="pt-price">{numericPrice && <sup>$</sup>}{item.price}</div>
      <div className="pt-period">/ {item.term}</div>
      <ul className="pt-features">
        {item.plans.map((p, i) => <li key={i}><CheckIcon />{p}</li>)}
      </ul>
      <a href={item.buttonLink || "#"} className="pt-btn">{item.buttonTitle || "Get Started"}</a>
    </div>
  );
}

function Style04({ item }: { item: PricingPlan }) {
  return (
    <div className={`pt-04 ${item.isPopular ? "popular" : ""}`}>
      {item.isPopular && <div className="pt-badge">Most Popular</div>}
      <div className="pt-name">{item.title}</div>
      <div className="pt-price"><sup>$</sup>{item.price}</div>
      <div className="pt-period">/ {item.term}</div>
      <ul className="pt-features">
        {item.plans.map((p, i) => <li key={i}><CheckIcon />{p}</li>)}
      </ul>
      <a href={item.buttonLink || "#"} className="pt-btn">{item.buttonTitle || "Get Started"}</a>
    </div>
  );
}

function CheckIcon() {
  return (
    <svg className="w-4 h-4 text-[--primary] flex-shrink-0" viewBox="0 0 16 16" fill="currentColor">
      <path d="M13.854 3.646a.5.5 0 0 1 0 .708l-7 7a.5.5 0 0 1-.708 0l-3.5-3.5a.5.5 0 1 1 .708-.708L6.5 10.293l6.646-6.647a.5.5 0 0 1 .708 0z" />
    </svg>
  );
}

function Style01({ item }: { item: PricingPlan }) {
  return (
    <div className={`pt-01 ${item.isPopular ? "popular" : ""}`}>
      {item.isPopular && <div className="pt-badge">Most Popular</div>}
      <div className="pt-title">{item.title}</div>
      <div className="pt-price">
        <sup>$</sup>{item.price}
      </div>
      <span className="pt-term">/ {item.term}</span>
      <ul className="pt-features">
        {item.plans.map((p, i) => (
          <li key={i}><CheckIcon />{p}</li>
        ))}
      </ul>
      <a href={item.buttonLink || "#"}
        className={`btn w-full justify-center ${item.isPopular ? "btn-fancy-primary" : "btn-fancy-outline"}`}>
        {item.buttonTitle || "Get Started"}
      </a>
    </div>
  );
}

function Style02({ item }: { item: PricingPlan }) {
  return (
    <div className={`pt-02 ${item.isPopular ? "popular" : ""}`}>
      <div className="pt-icon">{item.icon || "⭐"}</div>
      <div className="pt-title">{item.title}</div>
      <div className="pt-price"><sup>$</sup>{item.price}</div>
      <span className="pt-term block mb-4">/ {item.term}</span>
      <ul className="pt-features">
        {item.plans.map((p, i) => (
          <li key={i} className="flex items-center gap-2"><CheckIcon />{p}</li>
        ))}
      </ul>
      <a href={item.buttonLink || "#"}
        className={`btn mt-4 w-full justify-center ${item.isPopular ? "btn-gradient" : "btn-fancy-outline"}`}>
        {item.buttonTitle || "Get Started"}
      </a>
    </div>
  );
}
